// Drop messages missing required fields
  const required = ["device_id", "temperature", "timestamp"];
  for (const field of required) {
      if (msg.payload[field] === undefined) {
          node.warn("Invalid payload — missing: " + field);
          return null; // drop
      }
  }

  const t = msg.payload.temperature;
  if (typeof t !== "number" || t < -50 || t > 100) {
      node.warn("Temperature out of range: " + t);
      return null;
  }

  // High-temp alarm → alerts/<device_id>
  if (t > 30) {
      node.send([msg, {
          topic: "alerts/" + msg.payload.device_id,
          payload: { device: msg.payload.device_id, temperature:
  t }
      }]);
      return null;
  }

  return msg; // pass through

var policy = {
      devices: {
          sensor_01: {
              allowed_topics: ["telemetry/sensor_01"],
              rate_limit_msg_per_sec: 2,
              enabled: true
          }
      },
      default_policy: "deny"
  };

  var deviceId = msg.payload.device_id;
  var topic    = msg.topic;

  // 1. Unknown device → drop
  if (!policy.devices[deviceId]) {
      node.warn("Unknown device: " + deviceId);
      return null;
  }

  var dev = policy.devices[deviceId];

  // 2. Disabled device → drop
  if (!dev.enabled) {
      return null;
  }

  // 3. Wrong topic → alert + drop
  if (!dev.allowed_topics.includes(topic)) {
      return [null, {
          topic: "alerts/policy",
          payload: { device: deviceId, violation: "wrong_topic",
   topic: topic }
      }];
  }

  // 4. Rate limit
  var rates = context.get("rates") || {};
  var now   = Date.now();
  if (!rates[deviceId] || now - rates[deviceId].ts > 1000) {
      rates[deviceId] = { count: 0, ts: now };
  }
  rates[deviceId].count++;
  context.set("rates", rates);

  if (rates[deviceId].count > dev.rate_limit_msg_per_sec) {
      return [null, {
          topic: "alerts/ratelimit",
          payload: { device: deviceId, rate:
  rates[deviceId].count }
      }];
  }

  return msg;

// ─── Flood detection
  var deviceId = msg.payload.device_id;
  var counts   = context.get("counts") || {};
  var now      = Date.now();

  if (!counts[deviceId] || now - counts[deviceId].window > 1000)
  {
      counts[deviceId] = { count: 0, window: now };
  }
  counts[deviceId].count++;
  context.set("counts", counts);

  if (counts[deviceId].count > 10) {
      node.warn("FLOOD ALERT: " + deviceId);
      node.send([null, {
          topic: "alerts/flood",
          payload: { device: deviceId, count:
  counts[deviceId].count }
      }]);
      return null;
  }

  // ─── Metrics counter
  var metrics = context.global.get("metrics") || {
      messages_total: 0,
      alerts_total:   0,
      blocked_total:  0
  };
  metrics.messages_total++;
  context.global.set("metrics", metrics);

  return msg;

var metrics = context.global.get("metrics") || {
      messages_total: 0,
      alerts_total:   0,
      blocked_total:  0
  };

  msg.payload = [
      "# HELP mqtt_messages_total Total MQTT messages processed",
      "# TYPE mqtt_messages_total counter",
      "mqtt_messages_total " + metrics.messages_total,
      "# HELP mqtt_alerts_total Total security alerts generated",
      "# TYPE mqtt_alerts_total counter",
      "mqtt_alerts_total " + metrics.alerts_total,
      "# HELP mqtt_blocked_total Total dropped/blocked messages",
      "# TYPE mqtt_blocked_total counter",
      "mqtt_blocked_total " + metrics.blocked_total
  ].join("\n");

  msg.headers = { "content-type": "text/plain; version=0.0.4" };
  return msg;
